import pull from "../../../../../../../../../../../subject_repositories/pull-stream/pull.js"

describe("pull", () => {
  it("should complete synchronously when piping source through a through stream to a sink", () => {
    const results: number[] = []

    const source = (end: any, cb: Function) => {
      cb(end || null, end ? null : 42)
    }

    const through = (read: Function) => (end: any, cb: Function) => {
      read(end, cb)
    }

    const sink = (read: Function) => {
      read(null, (end: any, data: any) => {
        if (!end) results.push(data)
      })
    }

    pull(source, through, sink)
    expect(results).toEqual([42])
  })
})
